### GraphQL Testing in Depth

#### Testing Queries, Mutations, and Subscriptions

```python
import requests
import pytest

class TestGraphQLAPI:
    BASE_URL = "http://localhost:4000/graphql"

    def graphql(self, query, variables=None):
        response = requests.post(self.BASE_URL, json={
            "query": query,
            "variables": variables or {}
        })
        data = response.json()
        if "errors" in data:
            pytest.fail(f"GraphQL errors: {data['errors']}")
        return data["data"]

    def test_nested_query(self):
        data = self.graphql("""
            query {
                users(limit: 5) {
                    id
                    name
                    posts {
                        title
                        comments {
                            body
                            author { name }
                        }
                    }
                }
            }
        """)
        users = data["users"]
        assert len(users) <= 5
        for user in users:
            assert "id" in user
            assert isinstance(user["posts"], list)

    def test_query_with_fragments(self):
        data = self.graphql("""
            fragment UserFields on User {
                id
                name
                email
            }

            query {
                user1: user(id: "1") { ...UserFields }
                user2: user(id: "2") { ...UserFields }
            }
        """)
        assert data["user1"]["id"] != data["user2"]["id"]

    def test_mutation_with_validation(self):
        data = self.graphql("""
            mutation CreatePost($input: PostInput!) {
                createPost(input: $input) {
                    id
                    title
                    published
                }
            }
        """, variables={"input": {"title": "Test Post", "body": "Content", "published": False}})
        assert data["createPost"]["title"] == "Test Post"
        assert data["createPost"]["published"] is False
```

#### Testing GraphQL Error Handling

```python
def test_query_validation_error(self):
    response = requests.post(self.BASE_URL, json={
        "query": "{ nonExistentField }"
    })
    data = response.json()
    assert "errors" in data
    assert any("Cannot query field" in e["message"] for e in data["errors"])

def test_query_depth_limit(self):
    """APIs should limit query depth to prevent abuse."""
    deep_query = "{ users { posts { comments { author { posts { comments { author { name } } } } } } } }"
    response = requests.post(self.BASE_URL, json={"query": deep_query})
    data = response.json()
    assert "errors" in data  # Should reject deeply nested queries
```

### gRPC Testing in Depth

```python
import grpc
import pytest
from google.protobuf.json_format import MessageToDict

# Proto definition:
# service OrderService {
#   rpc CreateOrder(CreateOrderRequest) returns (Order);
#   rpc StreamOrders(StreamRequest) returns (stream Order);
#   rpc BulkCreate(stream CreateOrderRequest) returns (BulkResponse);
# }

class TestGRPCOrderService:
    @pytest.fixture(autouse=True)
    def setup(self):
        self.channel = grpc.insecure_channel("localhost:50051")
        self.stub = order_pb2_grpc.OrderServiceStub(self.channel)
        yield
        self.channel.close()

    def test_unary_call(self):
        request = order_pb2.CreateOrderRequest(
            customer_id=123,
            items=[order_pb2.OrderItem(product_id=1, quantity=2)]
        )
        response = self.stub.CreateOrder(request)
        assert response.id > 0
        assert response.status == order_pb2.OrderStatus.PENDING

    def test_server_streaming(self):
        """Server returns a stream of orders."""
        request = order_pb2.StreamRequest(customer_id=123)
        orders = list(self.stub.StreamOrders(request))
        assert len(orders) > 0
        for order in orders:
            assert order.customer_id == 123

    def test_client_streaming(self):
        """Client sends a stream of requests."""
        def order_requests():
            for i in range(5):
                yield order_pb2.CreateOrderRequest(
                    customer_id=123,
                    items=[order_pb2.OrderItem(product_id=i, quantity=1)]
                )
        response = self.stub.BulkCreate(order_requests())
        assert response.created_count == 5

    def test_grpc_error_handling(self):
        request = order_pb2.CreateOrderRequest(customer_id=-1)
        with pytest.raises(grpc.RpcError) as exc_info:
            self.stub.CreateOrder(request)
        assert exc_info.value.code() == grpc.StatusCode.INVALID_ARGUMENT

    def test_grpc_deadline(self):
        """Test that the service respects deadlines."""
        request = order_pb2.SlowRequest()
        with pytest.raises(grpc.RpcError) as exc_info:
            self.stub.SlowMethod(request, timeout=0.1)  # 100ms deadline
        assert exc_info.value.code() == grpc.StatusCode.DEADLINE_EXCEEDED
```

### WebSocket Testing in Depth

```python
import asyncio
import websockets
import json
import pytest

@pytest.mark.asyncio
async def test_websocket_chat():
    async with websockets.connect("ws://localhost:8080/chat") as ws:
        # Join a room
        await ws.send(json.dumps({"action": "join", "room": "test-room"}))
        response = json.loads(await ws.recv())
        assert response["type"] == "joined"

        # Send a message
        await ws.send(json.dumps({"action": "message", "text": "Hello!"}))
        response = json.loads(await ws.recv())
        assert response["type"] == "message"
        assert response["text"] == "Hello!"

@pytest.mark.asyncio
async def test_websocket_multiple_clients():
    async with websockets.connect("ws://localhost:8080/chat") as ws1, \
               websockets.connect("ws://localhost:8080/chat") as ws2:
        # Both join the same room
        await ws1.send(json.dumps({"action": "join", "room": "shared"}))
        await ws2.send(json.dumps({"action": "join", "room": "shared"}))
        await ws1.recv()  # join confirmation
        await ws2.recv()  # join confirmation

        # ws1 sends, ws2 receives
        await ws1.send(json.dumps({"action": "message", "text": "From client 1"}))
        await ws1.recv()  # echo back to sender
        msg = json.loads(await ws2.recv())
        assert msg["text"] == "From client 1"

@pytest.mark.asyncio
async def test_websocket_reconnection():
    ws = await websockets.connect("ws://localhost:8080/ws")
    await ws.close()
    # Reconnect should work
    ws = await websockets.connect("ws://localhost:8080/ws")
    await ws.send(json.dumps({"ping": True}))
    response = json.loads(await ws.recv())
    assert response.get("pong") is True
    await ws.close()
```
